from typing import List

class Solution:
    def is_prime(self, n: int) -> bool:
        if n <= 1:
            return False
        for i in range(2, int(n ** 0.5) + 1):
            if n % i == 0:
                return False
        return True

# Driver code
if __name__ == '__main__':
    s = Solution()
    print(s.is_prime(2))  # True
    print(s.is_prime(11))  # True
    print(s.is_prime(20))  # False

