#include <iostream>

class Solution {
public:
bool isPrime(int n) {
	if (n <= 1) return false;
	for (int i = 2; i <= sqrt(n); i++)
		if (n % i == 0)
			return false;
	return true;
}
};

int main() {
    Solution s;
    std::cout << (s.isPrime(2) ? "True" : "False") << std::endl;
    std::cout << (s.isPrime(11) ? "True" : "False") << std::endl;
    std::cout << (s.isPrime(20) ? "True" : "False") << std::endl;
    return 0;
}
